import Foundation

func solve(code: [String], businessLine: [String], isActive: [Bool]) -> [String] {
    var validCoupons = [(String, String)]()

    let businessOrder = ["electronics", "grocery", "pharmacy", "restaurant"]
    let businessPriority: [String: Int] = businessOrder.enumerated().reduce(into: [:]) { dict, element in
        dict[element.element] = element.offset
    }

    for i in 0..<code.count {
        let c = code[i]
        let bl = businessLine[i]
        let a = isActive[i]

        if c.isEmpty {
            continue
        }

        var isValid = true
        for char in c {
