            }
        }
        if !isValid {
            continue
        }

        if !businessOrder.contains(bl) {
            continue
        }

        if !a {
            continue
        }

        validCoupons.append( (bl, c) )
    }

    validCoupons.sort { (a, b) -> Bool in
        let priorityA = businessPriority[a.0]!
        let priorityB = businessPriority[b.0]!
        if priorityA != priorityB {
            return priorityA < priorityB
        } else {
            return a.1 < b.1
        }
    }

    return validCoupons.map { $0.1 }
}
