import Foundation

func solve(code: [String], businessLine: [String], isActive: [Bool]) -> [String] {
    var validCoupons = [(String, String)]()

    let businessOrder = ["electronics", "grocery", "pharmacy", "restaurant"]
    let businessPriority: [String: Int] = businessOrder.enumerated().reduce(into: [:]) { dict, element in
        dict[element.element] = element.offset
    }

    for i in 0..<code.count {
        let c = code[i]
        let bl = businessLine[i]
        let a = isActive[i]

        if c.isEmpty {
            continue
        }

        var isValid = true
        for char in c {
            if !"a-zA-Z0-9_".contains(char) {
                isValid = false
                break
            }
        }
        if !isValid {
            continue
        }

        if !businessOrder.contains(bl) {
            continue
        }

        if !a {
            continue
        }

        validCoupons.append( (bl, c) )
    }

    // Sort the valid coupons
    validCoupons.sort { (a, b) -> Bool in
        let priorityA = businessPriority[a.0]!
        let priorityB = businessPriority[b.0]!
        if priorityA != priorityB {
            return priorityA < priorityB
        } else {
            return a.1 < b.1
        }
    }

    return validCoupons.map { $0.1 }
}

